const promises=[["Proverbios 3:5", "Confía en Jehová con todo tu corazón."], ["Salmo 46:1", "Dios es nuestro amparo y fortaleza."], ["Josué 1:9", "Esfuérzate y sé valiente."], ["Filipenses 4:13", "Todo lo puedo en Cristo que me fortalece."], ["Isaías 41:10", "No temas, porque yo estoy contigo."]];
let currentFilter='todos';
function get(k,f){try{return JSON.parse(localStorage.getItem(k))??f}catch(e){return f}}
function set(k,v){localStorage.setItem(k,JSON.stringify(v))}
function show(id){document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));document.getElementById(id).classList.add('active');if(id==='juegos')renderGames();if(id==='calendario')renderCalendar();if(id==='progreso')renderProgress();window.scrollTo({top:0,behavior:'smooth'})}
function renderDevos(){let done=get('doneDevos',[]);devoBox.innerHTML=devos.map((d,i)=>`<div class="card ${done.includes(i)?'done':''}"><span class="badge">${d[0]}</span><h3>${d[1]}</h3><p class="verse"><b>${d[2]}</b></p><p>${d[3]}</p><p><b>Oración:</b> ${d[4]}</p><p><b>Aplicación:</b> ${d[5]}</p><button class="primary" onclick="toggleDevo(${i})">${done.includes(i)?'Completado ✓':'Marcar completado'}</button></div>`).join('')}
function toggleDevo(i){let a=get('doneDevos',[]);a=a.includes(i)?a.filter(x=>x!==i):[...a,i];set('doneDevos',a);renderDevos();renderCalendar();renderProgress()}
function filterGames(f){currentFilter=f;renderGames()}
function renderGames(){let done=get('doneGames',[]);let list=games.map((g,i)=>({...g,idx:i}));if(currentFilter==='pendientes')list=list.filter(g=>!done.includes(g.idx));if(currentFilter==='completados')list=list.filter(g=>done.includes(g.idx));gamesBox.innerHTML=list.map(g=>`<div class="card ${done.includes(g.idx)?'done':''}"><span class="badge">Día ${g.day}</span><div class="gameType">${g.type}</div><h3>🏆 ${g.title}</h3><p>${g.prompt}</p><textarea id="gameResponse${g.idx}" placeholder="Escribe tu respuesta o reflexión...">${get('gameResponses',{})[g.idx]||''}</textarea><button class="secondary" onclick="saveGameResponse(${g.idx})">Guardar respuesta</button><button class="secondary" onclick="showAnswer(${g.idx})">Ver ayuda / respuesta</button><div class="answerBox" id="answer${g.idx}"><b>Respuesta:</b> ${g.answer}<br><span class="rewardTag">${g.reward}</span></div><button class="primary" onclick="toggleGame(${g.idx})">${done.includes(g.idx)?'Completado ✓':'Completar y ganar flor'}</button></div>`).join('')||'<div class="card">No hay juegos en este filtro.</div>';renderGarden();}
function showAnswer(i){document.getElementById('answer'+i).style.display='block'}
function saveGameResponse(i){let r=get('gameResponses',{});let el=document.getElementById('gameResponse'+i);if(el)r[i]=el.value;set('gameResponses',r);alert('Respuesta guardada 💜')}
function toggleGame(i){let a=get('doneGames',[]);a=a.includes(i)?a.filter(x=>x!==i):[...a,i];set('doneGames',a);renderGames();renderProgress()}
function renderGarden(){let done=get('doneGames',[]);gardenBox.innerHTML=done.length?done.map(i=>`<div class="flowerReward">${(games[i]?.reward||'🌸').split(' ')[0]}</div>`).join(''):'<p>Completa juegos para llenar tu jardín de flores 🌱</p>';gameProgressText.textContent=`Juegos completados: ${done.length}/31`;}
function addPrayer(){let a=get('prayers',[]);a.push({id:Date.now(),name:pName.value,need:pNeed.value,done:false});set('prayers',a);pName.value='';pNeed.value='';renderPrayers()}
function renderPrayers(){let a=get('prayers',[]);prayerBox.innerHTML=a.map(p=>`<div class="card"><h3>${p.name||'Petición'}</h3><p>${p.need}</p><button class="secondary" onclick="togglePrayer(${p.id})">${p.done?'Contestada ✓':'Marcar contestada'}</button></div>`).join('')||'<div class="card">Añade tu primera petición.</div>'}
function togglePrayer(id){let a=get('prayers',[]);let p=a.find(x=>x.id===id);if(p)p.done=!p.done;set('prayers',a);renderPrayers();renderProgress()}
function saveJournal(){let e=get('journal',[]);e.push({date:jDate.value||new Date().toISOString().slice(0,10),text:jText.value,thanks:jThanks.value});set('journal',e);jText.value='';jThanks.value='';renderJournal()}
function renderJournal(){let e=get('journal',[]);journalBox.innerHTML=e.slice().reverse().map(x=>`<div class="card"><h3>${x.date}</h3><p>${x.text}</p><p><b>Gratitud:</b> ${x.thanks}</p></div>`).join('')}
function renderCalendar(){let done=get('doneDevos',[]);calendarBox.innerHTML='';for(let i=0;i<31;i++)calendarBox.innerHTML+=`<button class="day ${done.includes(i)?'doneDay':''}">${i+1}<br>${done.includes(i)?'✓':''}</button>`}
function renderPromises(){promisesBox.innerHTML=promises.map(p=>`<div class="card"><h3>${p[0]}</h3><p>${p[1]}</p></div>`).join('')}
function renderProgress(){let d=get('doneDevos',[]).length,g=get('doneGames',[]).length,p=get('prayers',[]).filter(x=>x.done).length;progressCircle.textContent=Math.round(d/31*100)+'%';progressText.textContent=`Devocionales: ${d}/31 • Juegos: ${g}/31 • Oraciones contestadas: ${p}`;}
function downloadBackup(){let data={doneDevos:get('doneDevos',[]),doneGames:get('doneGames',[]),gameResponses:get('gameResponses',{}),prayers:get('prayers',[]),journal:get('journal',[])};let blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='respaldo-jardin-oracion.json';a.click()}
jDate.value=new Date().toISOString().slice(0,10);renderDevos();renderGames();renderGarden();renderPrayers();renderJournal();renderCalendar();renderPromises();renderProgress();

/* Extras de creadora, certificado e insignias */
function saveSpecialPrayer(){
  const name = document.getElementById('specialPrayerName')?.value || 'Petición especial';
  const text = document.getElementById('specialPrayerText')?.value || '';
  if(!text.trim()){ alert('Escribe una petición primero 💜'); return; }
  let a = get('prayers', []);
  a.push({id:Date.now(), name:name, need:text, done:false, special:true});
  set('prayers', a);
  document.getElementById('specialPrayerName').value='';
  document.getElementById('specialPrayerText').value='';
  renderPrayers();
  alert('Petición especial guardada en tu Jardín de Oración 💜');
}

function renderBadges(){
  const d = get('doneDevos',[]).length;
  const g = get('doneGames',[]).length;
  const p = get('prayers',[]).filter(x=>x.done).length;
  let badges = [];
  if(d >= 7) badges.push('📖 Mujer de la Palabra');
  if(d >= 15) badges.push('🌸 Mujer de Fe');
  if(g >= 10) badges.push('🏆 Guerrera Bíblica');
  if(g >= 20) badges.push('🌿 Jardín Floreciente');
  if(p >= 1) badges.push('🙏 Intercesora');
  if(d >= 31) badges.push('💜 Mes Completado');
  return badges;
}

const oldRenderProgress = typeof renderProgress === 'function' ? renderProgress : null;
renderProgress = function(){
  if(oldRenderProgress) oldRenderProgress();
  const card = document.getElementById('progressText');
  if(card){
    const badges = renderBadges();
    const badgeHTML = badges.length ? '<div class="badgeBox">'+badges.map(b=>`<span class="spiritualBadge">${b}</span>`).join('')+'</div>' : '<p class="soft">Completa devocionales y juegos para ganar insignias espirituales.</p>';
    card.innerHTML = card.textContent + badgeHTML;
  }
  const certStatus = document.getElementById('certificateStatus');
  if(certStatus){
    const completed = get('doneDevos',[]).length;
    certStatus.textContent = completed >= 31 ? 'Tu certificado está listo para imprimir 💜' : `Completa los 31 devocionales para finalizar tu recorrido. Llevas ${completed}/31.`;
  }
};

document.addEventListener('DOMContentLoaded', function(){
  if(typeof renderProgress === 'function') renderProgress();
});
setTimeout(function(){ if(typeof renderProgress === 'function') renderProgress(); }, 400);


