let promiseView = 'todas';
let selectedPromiseCategory = '';
let currentPromiseList = [];

function setPromiseView(view){
  promiseView = view;
  selectedPromiseCategory = '';
  renderPromises();
}

function setPromiseCategory(cat){
  promiseView = 'categorias';
  selectedPromiseCategory = cat;
  renderPromises();
}

function allPromises(){
  return [...promiseLibrary, ...get('customPromises', [])];
}

function renderDailyPromise(){
  const p = promiseLibrary[new Date().getDate() % promiseLibrary.length];
  const text = document.getElementById('dailyPromiseText');
  const ref = document.getElementById('dailyPromiseRef');
  if(text) text.textContent = '“' + p.text + '”';
  if(ref) ref.textContent = p.ref;
}

function favoriteDailyPromise(){
  const p = promiseLibrary[new Date().getDate() % promiseLibrary.length];
  togglePromiseFavoriteObject(p);
}

function renderPromiseCategories(){
  const box = document.getElementById('promiseCategoryBox');
  if(!box) return;
  const cats = ['Paz','Fe','Esperanza','Fortaleza','Sanidad','Familia','Matrimonio','Protección','Salvación','Espíritu Santo','Oración'];
  if(promiseView !== 'categorias'){ box.innerHTML = ''; return; }
  box.innerHTML = cats.map(c => `<button class="categoryBtn" onclick="setPromiseCategory('${c}')">💜 ${c}</button>`).join('');
}

function renderPromises(){
  renderDailyPromise();
  renderPromiseCategories();

  const box = document.getElementById('promisesBox');
  if(!box) return;

  const q = (document.getElementById('promiseSearch')?.value || '').toLowerCase();
  const favs = get('favoritePromises', []);
  let list = allPromises();

  if(promiseView === 'favoritas') list = list.filter(p => favs.some(f => f.ref === p.ref && f.text === p.text));
  if(promiseView === 'mias') list = get('customPromises', []);
  if(promiseView === 'categorias' && selectedPromiseCategory) list = list.filter(p => p.cat === selectedPromiseCategory);
  if(q) list = list.filter(p => (p.ref + ' ' + p.text + ' ' + (p.cat||'')).toLowerCase().includes(q));

  currentPromiseList = list;

  box.innerHTML = list.map((p, i) => {
    const isFav = favs.some(f => f.ref === p.ref && f.text === p.text);
    return `<div class="card promiseCard">
      <span class="categoryPill">${p.cat || 'Promesa'}</span>
      <h3>${p.ref}</h3>
      <p>${p.text}</p>
      ${p.note ? `<p><b>Reflexión:</b> ${p.note}</p>` : ''}
      <div class="promiseActions">
        <button class="secondary" onclick="togglePromiseFavoriteByIndex(${i})">${isFav ? '❤️ Favorita' : '🤍 Guardar'}</button>
        <button class="secondary" onclick="copyPromiseByIndex(${i})">📋 Copiar</button>
      </div>
    </div>`;
  }).join('') || '<div class="card">No hay promesas en esta sección todavía.</div>';
}

function togglePromiseFavoriteByIndex(i){
  const p = currentPromiseList[i];
  if(p) togglePromiseFavoriteObject(p);
}

function togglePromiseFavoriteObject(p){
  let favs = get('favoritePromises', []);
  const exists = favs.some(f => f.ref === p.ref && f.text === p.text);
  favs = exists ? favs.filter(f => !(f.ref === p.ref && f.text === p.text)) : [...favs, p];
  set('favoritePromises', favs);
  renderPromises();
}

function copyPromiseByIndex(i){
  const p = currentPromiseList[i];
  if(!p) return;
  const full = p.ref + ' - ' + p.text;
  if(navigator.clipboard) navigator.clipboard.writeText(full);
  alert('Promesa copiada 💜');
}

function addCustomPromise(){
  const ref = document.getElementById('newPromiseRef')?.value.trim();
  const text = document.getElementById('newPromiseText')?.value.trim();
  const note = document.getElementById('newPromiseNote')?.value.trim();
  const cat = document.getElementById('newPromiseCategory')?.value || 'Fe';
  if(!ref || !text){ alert('Escribe la referencia y el texto de la promesa 💜'); return; }
  const custom = get('customPromises', []);
  custom.push({ref, text, note, cat});
  set('customPromises', custom);
  document.getElementById('newPromiseRef').value = '';
  document.getElementById('newPromiseText').value = '';
  document.getElementById('newPromiseNote').value = '';
  promiseView = 'mias';
  renderPromises();
  alert('Promesa guardada 💜');
}

setTimeout(renderPromises, 300);
document.addEventListener('DOMContentLoaded', renderPromises);


