let promiseViewFixed = 'todas';
let selectedPromiseCategoryFixed = '';
let currentPromiseListFixed = [];

function setPromiseView(view){
  promiseViewFixed = view;
  selectedPromiseCategoryFixed = '';
  renderPromises();
}

function setPromiseCategory(cat){
  promiseViewFixed = 'categorias';
  selectedPromiseCategoryFixed = cat;
  renderPromises();
}

function allPromisesFixed(){
  return promiseLibraryFixed.concat(get('customPromises', []));
}

function renderDailyPromise(){
  const p = promiseLibraryFixed[new Date().getDate() % promiseLibraryFixed.length];
  const text = document.getElementById('dailyPromiseText');
  const ref = document.getElementById('dailyPromiseRef');
  if(text) text.textContent = '“' + p.text + '”';
  if(ref) ref.textContent = p.ref;
}

function favoriteDailyPromise(){
  const p = promiseLibraryFixed[new Date().getDate() % promiseLibraryFixed.length];
  togglePromiseFavoriteObject(p);
}

function renderPromiseCategories(){
  const box = document.getElementById('promiseCategoryBox');
  if(!box) return;
  const cats = ['Paz','Fe','Esperanza','Fortaleza','Sanidad','Familia','Matrimonio','Protección','Salvación','Espíritu Santo','Oración'];
  if(promiseViewFixed !== 'categorias'){
    box.innerHTML = '';
    return;
  }
  box.innerHTML = cats.map(function(c){
    return '<button class="categoryBtn" onclick="setPromiseCategory(\'' + c + '\')">💜 ' + c + '</button>';
  }).join('');
}

function renderPromises(){
  renderDailyPromise();
  renderPromiseCategories();

  const box = document.getElementById('promisesBox');
  if(!box) return;

  const searchEl = document.getElementById('promiseSearch');
  const q = searchEl ? searchEl.value.toLowerCase() : '';
  const favs = get('favoritePromises', []);
  let list = allPromisesFixed();

  if(promiseViewFixed === 'favoritas') {
    list = list.filter(function(p){ return favs.some(function(f){ return f.ref === p.ref && f.text === p.text; }); });
  }
  if(promiseViewFixed === 'mias') list = get('customPromises', []);
  if(promiseViewFixed === 'categorias' && selectedPromiseCategoryFixed) {
    list = list.filter(function(p){ return p.cat === selectedPromiseCategoryFixed; });
  }
  if(q) {
    list = list.filter(function(p){
      return (p.ref + ' ' + p.text + ' ' + (p.cat || '')).toLowerCase().includes(q);
    });
  }

  currentPromiseListFixed = list;

  if(!list.length){
    box.innerHTML = '<div class="card">No hay promesas en esta sección todavía.</div>';
    return;
  }

  box.innerHTML = list.map(function(p, i){
    const isFav = favs.some(function(f){ return f.ref === p.ref && f.text === p.text; });
    return '<div class="card promiseCard">' +
      '<span class="categoryPill">' + (p.cat || 'Promesa') + '</span>' +
      '<h3>' + p.ref + '</h3>' +
      '<p>' + p.text + '</p>' +
      (p.note ? '<p><b>Reflexión:</b> ' + p.note + '</p>' : '') +
      '<div class="promiseActions">' +
      '<button class="secondary" onclick="togglePromiseFavoriteByIndex(' + i + ')">' + (isFav ? '❤️ Favorita' : '🤍 Guardar') + '</button>' +
      '<button class="secondary" onclick="copyPromiseByIndex(' + i + ')">📋 Copiar</button>' +
      '</div></div>';
  }).join('');
}

function togglePromiseFavoriteByIndex(i){
  const p = currentPromiseListFixed[i];
  if(p) togglePromiseFavoriteObject(p);
}

function togglePromiseFavoriteObject(p){
  let favs = get('favoritePromises', []);
  const exists = favs.some(function(f){ return f.ref === p.ref && f.text === p.text; });
  favs = exists ? favs.filter(function(f){ return !(f.ref === p.ref && f.text === p.text); }) : favs.concat([p]);
  set('favoritePromises', favs);
  renderPromises();
}

function copyPromiseByIndex(i){
  const p = currentPromiseListFixed[i];
  if(!p) return;
  const full = p.ref + ' - ' + p.text;
  if(navigator.clipboard) navigator.clipboard.writeText(full);
  alert('Promesa copiada 💜');
}

function addCustomPromise(){
  const refEl = document.getElementById('newPromiseRef');
  const textEl = document.getElementById('newPromiseText');
  const noteEl = document.getElementById('newPromiseNote');
  const catEl = document.getElementById('newPromiseCategory');
  const ref = refEl ? refEl.value.trim() : '';
  const text = textEl ? textEl.value.trim() : '';
  const note = noteEl ? noteEl.value.trim() : '';
  const cat = catEl ? catEl.value : 'Fe';
  if(!ref || !text){
    alert('Escribe la referencia y el texto de la promesa 💜');
    return;
  }
  const custom = get('customPromises', []);
  custom.push({ref: ref, text: text, note: note, cat: cat});
  set('customPromises', custom);
  refEl.value = '';
  textEl.value = '';
  if(noteEl) noteEl.value = '';
  promiseViewFixed = 'mias';
  renderPromises();
  alert('Promesa guardada 💜');
}

document.addEventListener('DOMContentLoaded', function(){ renderPromises(); });
setTimeout(function(){ renderPromises(); }, 300);
setTimeout(function(){ renderPromises(); }, 1000);


