function renderDevos(){
  const box = document.getElementById('devoBox');
  if(!box) return;
  const done = get('doneDevos', []);
  box.innerHTML = deepDevotionals.map(function(d, i){
    const isDone = done.includes(i);
    return '<div class="card devoDeepCard ' + (isDone ? 'done' : '') + '">' +
      '<span class="badge">Día ' + d.day + '</span>' +
      '<h3>' + d.title + '</h3>' +
      '<p class="verse"><b>' + d.verse + '</b></p>' +
      '<p class="devoSectionTitle">🌷 Reflexión</p>' +
      '<p class="devoReflection">' + d.reflection + '</p>' +
      '<p class="devoSectionTitle">🙏 Oración</p>' +
      '<p>' + d.prayer + '</p>' +
      '<div class="devoQuestion"><b>✍️ Para escribir en tu diario:</b><br>' + d.question + '</div>' +
      '<div class="devoPromise">💜 Promesa: ' + d.promise + '</div>' +
      '<button class="primary" onclick="toggleDevo(' + i + ')">' + (isDone ? 'Completado ✓' : 'Marcar completado') + '</button>' +
      '</div>';
  }).join('');
}

function toggleDevo(i){
  let a = get('doneDevos', []);
  a = a.includes(i) ? a.filter(function(x){ return x !== i; }) : a.concat([i]);
  set('doneDevos', a);
  renderDevos();
  if(typeof renderCalendar === 'function') renderCalendar();
  if(typeof renderProgress === 'function') renderProgress();
}

document.addEventListener('DOMContentLoaded', function(){ renderDevos(); });
setTimeout(function(){ renderDevos(); }, 300);


/* Formato de fecha: Mes/Día/Año */
function jdFormatDateUS(dateString){
  if(!dateString) return '';
  // Supports YYYY-MM-DD from date input
  const parts = String(dateString).split('-');
  if(parts.length === 3){
    const y = parts[0];
    const m = parts[1].padStart(2,'0');
    const d = parts[2].padStart(2,'0');
    return m + '/' + d + '/' + y;
  }
  const dt = new Date(dateString);
  if(isNaN(dt)) return dateString;
  return String(dt.getMonth()+1).padStart(2,'0') + '/' + String(dt.getDate()).padStart(2,'0') + '/' + dt.getFullYear();
}

function jdTodayISO(){
  const d = new Date();
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}

// Override journal rendering so saved dates show MM/DD/YYYY
function renderJournal(){
  const box = document.getElementById('journalBox');
  if(!box) return;

  let entries = get('journal', []);
  // Some older versions used journalEntries object. Include it if present.
  const older = get('journalEntries', null);
  if(older && typeof older === 'object' && !Array.isArray(older)){
    Object.keys(older).forEach(function(k){
      if(older[k]) entries.push({date:k, text:older[k].text || older[k], thanks:older[k].thanks || ''});
    });
  }

  box.innerHTML = entries.slice().reverse().map(function(x){
    return '<div class="card">' +
      '<h3>' + jdFormatDateUS(x.date) + '</h3>' +
      '<p>' + (x.text || '') + '</p>' +
      (x.thanks ? '<p><b>Gratitud:</b> ' + x.thanks + '</p>' : '') +
      '</div>';
  }).join('') || '<div class="card">Aún no has escrito en tu diario.</div>';
}

// Override saveJournal to store ISO but display MM/DD/YYYY
function saveJournal(){
  const dateEl = document.getElementById('jDate');
  const textEl = document.getElementById('jText');
  const thanksEl = document.getElementById('jThanks');

  let entries = get('journal', []);
  entries.push({
    date: (dateEl && dateEl.value) ? dateEl.value : jdTodayISO(),
    text: textEl ? textEl.value : '',
    thanks: thanksEl ? thanksEl.value : ''
  });
  set('journal', entries);

  if(textEl) textEl.value = '';
  if(thanksEl) thanksEl.value = '';
  renderJournal();
}

// Make sure date input starts on today
document.addEventListener('DOMContentLoaded', function(){
  const dateEl = document.getElementById('jDate');
  if(dateEl && !dateEl.value) dateEl.value = jdTodayISO();
  renderJournal();
});
setTimeout(function(){
  const dateEl = document.getElementById('jDate');
  if(dateEl && !dateEl.value) dateEl.value = jdTodayISO();
  renderJournal();
}, 400);


/* FECHA USA FINAL - siempre Mes/Día/Año */
function jdPad(n){ return String(n).padStart(2,'0'); }

function jdTodayUS(){
  const d = new Date();
  return jdPad(d.getMonth()+1) + '/' + jdPad(d.getDate()) + '/' + d.getFullYear();
}

function jdNormalizeToUS(value){
  if(!value) return jdTodayUS();
  value = String(value).trim();

  // If old ISO date: YYYY-MM-DD -> MM/DD/YYYY
  if(/^\d{4}-\d{2}-\d{2}$/.test(value)){
    const p = value.split('-');
    return p[1] + '/' + p[2] + '/' + p[0];
  }

  // If already slash format, keep as typed.
  if(/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(value)){
    const p = value.split('/');
    return jdPad(p[0]) + '/' + jdPad(p[1]) + '/' + p[2];
  }

  const d = new Date(value);
  if(!isNaN(d)){
    return jdPad(d.getMonth()+1) + '/' + jdPad(d.getDate()) + '/' + d.getFullYear();
  }

  return value;
}

function jdUSDateToISO(us){
  // MM/DD/YYYY -> YYYY-MM-DD for sorting if needed
  if(!/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(us)) return us;
  const p = us.split('/');
  return p[2] + '-' + jdPad(p[0]) + '-' + jdPad(p[1]);
}

// Override saveJournal completely
function saveJournal(){
  const dateEl = document.getElementById('jDate');
  const textEl = document.getElementById('jText');
  const thanksEl = document.getElementById('jThanks');

  let entries = get('journal', []);
  const dateUS = jdNormalizeToUS(dateEl ? dateEl.value : '');

  entries.push({
    date: dateUS,
    text: textEl ? textEl.value : '',
    thanks: thanksEl ? thanksEl.value : ''
  });

  set('journal', entries);

  if(textEl) textEl.value = '';
  if(thanksEl) thanksEl.value = '';
  if(dateEl) dateEl.value = jdTodayUS();

  renderJournal();
}

// Override renderJournal completely
function renderJournal(){
  const box = document.getElementById('journalBox');
  if(!box) return;

  let entries = get('journal', []);

  box.innerHTML = entries.slice().reverse().map(function(x){
    const dateUS = jdNormalizeToUS(x.date);
    return '<div class="card">' +
      '<h3>' + dateUS + '</h3>' +
      '<p>' + (x.text || '') + '</p>' +
      (x.thanks ? '<p><b>Gratitud:</b> ' + x.thanks + '</p>' : '') +
      '</div>';
  }).join('') || '<div class="card">Aún no has escrito en tu diario.</div>';
}

// Force the visible date input to MM/DD/YYYY
function jdInitUSDate(){
  const dateEl = document.getElementById('jDate');
  if(dateEl){
    dateEl.type = 'text';
    dateEl.placeholder = 'MM/DD/YYYY';
    if(!dateEl.value || /^\d{4}-\d{2}-\d{2}$/.test(dateEl.value)){
      dateEl.value = jdNormalizeToUS(dateEl.value || jdTodayUS());
    }
  }
  renderJournal();
}

document.addEventListener('DOMContentLoaded', jdInitUSDate);
setTimeout(jdInitUSDate, 200);
setTimeout(jdInitUSDate, 800);
setTimeout(jdInitUSDate, 1500);


/* Envío de peticiones por Netlify Forms */
function jdEncodeForm(data){
  return new URLSearchParams(data).toString();
}

document.addEventListener('DOMContentLoaded', function(){
  const form = document.getElementById('specialPrayerForm');
  if(!form) return;

  form.addEventListener('submit', function(e){
    e.preventDefault();

    const nameEl = document.getElementById('specialPrayerName');
    const textEl = document.getElementById('specialPrayerText');
    const dateEl = document.getElementById('specialPrayerDate');
    const status = document.getElementById('specialPrayerStatus');

    const nombre = nameEl ? nameEl.value.trim() : '';
    const peticion = textEl ? textEl.value.trim() : '';

    if(!nombre || !peticion){
      if(status) status.textContent = 'Por favor escribe el nombre/título y la petición.';
      return;
    }

    const fecha = new Date().toLocaleString('es-US');
    if(dateEl) dateEl.value = fecha;

    // Guardar copia privada en el dispositivo de la usuaria
    try {
      const local = JSON.parse(localStorage.getItem('specialPrayers') || '[]');
      local.push({name:nombre, text:peticion, date:fecha});
      localStorage.setItem('specialPrayers', JSON.stringify(local));
    } catch(err) {}

    const formData = {
      'form-name': 'peticiones-oracion',
      'nombre': nombre,
      'peticion': peticion,
      'fecha': fecha
    };

    if(status) status.textContent = 'Enviando petición...';

    fetch('/', {
      method: 'POST',
      headers: {'Content-Type': 'application/x-www-form-urlencoded'},
      body: jdEncodeForm(formData)
    })
    .then(function(){
      if(status) status.textContent = 'Petición enviada correctamente. Estaremos orando por ti. 💜';
      if(nameEl) nameEl.value = '';
      if(textEl) textEl.value = '';
    })
    .catch(function(){
      if(status) status.textContent = 'No se pudo enviar ahora. La petición quedó guardada en tu dispositivo.';
    });
  });
});
